    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.CAR_INSURANCE_DISCOUNT],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
  {
    id: 6,
    text: 'Voucher para IPVA e outros débitos',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.IPVA_DISCOUNT],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
  {
    id: 7,
    text: 'Milhas aéreas',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.AIRLINE_MILES],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
];

const MOCK_LEARN_MORE_DATA = [
  {
    category: 'Como ganhar pontos',
    PK: 'param_1',
    dateCreated: '2024-01-01',
    dateUpdated: '2024-01-01',
    status: 1,
    value: {
      icon: 'icon-star' as any,
      order: 1,
      questions: [
        { question: 'Como funciona o programa?', answer: 'Você ganha pontos automaticamente.' },
      ],
    },
  },
  {
    category: 'Como usar pontos',
    PK: 'param_2',
    dateCreated: '2024-01-01',
    dateUpdated: '2024-01-01',
    status: 1,
    value: {
      icon: 'icon-benefits' as any,
      order: 2,
      questions: [
        { question: 'Onde posso usar?', answer: 'Vouchers, cashback e marketplace.' },
