import React, { useEffect, useState } from 'react';
import { ScrollView } from 'react-native';
import type { Meta, StoryObj } from '@storybook/react';
import {
  Box,
  CardActivity,
  CardMiddle,
  CardPoints,
  Header,
  Skeleton,
  Text,
} from '@semparar/design-system-app';
import { PropsCardMiddle } from '@semparar/design-system-app/src/atomic/molecules/Cards/CardMiddle/Models';
import { NavigationDecorator } from '../../.storybook/decorators/NavigationDecorator';
import type { PointsCardItem } from '../screens/Points/Models';
import { NAME_TO_ICON, KEY_NAME_TO_ICON } from '../screens/Points/data';
import { useRootStore } from '~/store';
import { formatPoints } from '../utils/formatPoints';

const MOCK_ITEMS: PointsCardItem[] = [
  {
    id: 1,
    text: 'Cashback na fatura',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.RESCUE_IN_INVOICE],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
  {
    id: 2,
    text: 'Shopping',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.MARKETPLACE],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
  {
    id: 3,
    text: 'Voucher para abastecimento',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.FUEL_VOUCHER],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
  {
    id: 4,
    text: 'Voucher para estacionamento',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.PARKING_DISCOUNT],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
  {
    id: 5,
    text: 'Voucher para seguro auto',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.CAR_INSURANCE_DISCOUNT],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
  {
    id: 6,
    text: 'Voucher para IPVA e outros débitos',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.IPVA_DISCOUNT],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
  {
    id: 7,
    text: 'Milhas aéreas',
    bgColor: '#F5F5FA',
    icon: NAME_TO_ICON[KEY_NAME_TO_ICON.AIRLINE_MILES],
    textAlign: 'center',
    iconColor: '#6200ee',
    onPress: () => {},
  },
];

const MOCK_LEARN_MORE_DATA = [
  {
    category: 'Como ganhar pontos',
    icon: 'icon-star' as any,
  },
  {
    category: 'Como usar pontos',
    icon: 'icon-benefits' as any,
  },
  {
    category: 'Regras do programa',
    icon: 'icon-document' as any,
  },
];

function seedStore(points: number) {
  const state = useRootStore.getState() as any;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setBalance(points);
  }
}

function LearnMoreSection({ isLoading }: { isLoading: boolean }) {
  if (isLoading) {
    return (
      <Box>
        <Text type="paragraphXXXL" mb="xxxs">
          Saiba mais
        </Text>
        {[1, 2, 3].map(i => (
          <Skeleton key={i} width={350} height={72} mb="xxs" />
        ))}
      </Box>
    );
  }

  return (
    <Box>
      <Text type="paragraphXXXL" mb="xxxs">
        Saiba mais
      </Text>
      {MOCK_LEARN_MORE_DATA.map(item => (
        <CardActivity
          key={item.category}
          title={item.category}
          titleTextType={'paragraphMD' as any}
          mt="nano"
          icon={item.icon}
          onPress={() => {}}
          showIcon
          showIconRight
          descriptionColor="INTENSE_COLOR_05"
          iconRight="icon-next"
          showButton={false}
          showTagLabel={false}
        />
      ))}
    </Box>
  );
}

function PointsStoryWrapper({
  points = 15320,
  isLoading = false,
}: {
  points?: number;
  isLoading?: boolean;
}) {
  const [isMyOrders, setIsMyOrders] = useState(false);

  useEffect(() => {
    seedStore(points);
  }, [points]);

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title={isMyOrders ? 'Meu espaço' : 'Programa de Pontos'}
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {
          if (isMyOrders) {
            setIsMyOrders(false);
          }
        }}
        isOption={!isMyOrders}
        iconRight="icon-menu"
        onPressIconRight={() => setIsMyOrders(true)}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        {isMyOrders ? (
          <CardActivity
            isLoading={isLoading}
            icon="icon-shopping-bag"
            showIcon
            showIconRight={false}
            hideBackground
            hideBorder
            title="Meus pedidos"
            titleTextType="paragraphXL"
            onPress={() => {}}
          />
        ) : (
          <Box ml="smaller" mr="smaller">
            <CardPoints
              icon="icon-benefits"
              iconInfo="icon-help"
              iconAction="icon-next"
              isLoading={isLoading}
              mt="smaller"
              mb="xs"
              onPressIconInfo={() => {}}
              onPressExtract={() => {}}
              textExtract="Extrato completo"
              title="Pontos disponíveis"
              valuePoints={formatPoints(points ?? 0)}
            />

            <Text type="paragraphXXXL" mb="xxxs">
              Onde usar meus pontos
            </Text>

            <CardMiddle
              items={MOCK_ITEMS as PropsCardMiddle['items']}
              renderType="grid"
              isLoading={isLoading}
              mb="xs"
            />

            <LearnMoreSection isLoading={isLoading} />
          </Box>
        )}
      </ScrollView>
    </Box>
  );
}

const meta: Meta<typeof PointsStoryWrapper> = {
