          key={item.category}
          title={item.category}
          titleTextType={'paragraphMD' as any}
          mt="nano"
          icon={item.icon}
          onPress={() => {}}
          showIcon
          showIconRight
          descriptionColor="INTENSE_COLOR_05"
          iconRight="icon-next"
          showButton={false}
          showTagLabel={false}
        />
      ))}
    </Box>
  );
}

