        hideLeftIcon={false}
        onBack={() => {
          if (isMyOrders) {
            setIsMyOrders(false);
          }
        }}
        isOption={!isMyOrders}
        iconRight="icon-menu"
        onPressIconRight={() => setIsMyOrders(true)}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        {isMyOrders ? (
          <CardActivity
            isLoading={isLoading}
            icon="icon-shopping-bag"
            showIcon
            showIconRight={false}
            hideBackground
            hideBorder
            title="Meus pedidos"
            titleTextType="paragraphXL"
            onPress={() => {}}
          />
        ) : (
